# Restore agent session from a saved summary (cross-session memory)
# Store the summary externally (Redis, DB) keyed by session_id
# Inject it as the first message pair on session resume

import json, time

def save_session_summary(
    session_id: str,
    summary: str,
    storage: dict,    # replace with Redis/DB in production
) -> None:
    storage[session_id] = {
        'summary':    summary,
        'saved_at':   time.time(),
    }

def restore_session(
    session_id: str,
    storage: dict,
) -> list[dict]:
    record = storage.get(session_id)
    if not record:
        return []  # new session, no prior history
    summary = record['summary']
    return [
        {
            'role': 'user',
            'content': (
                '[Resuming previous session. Here is a summary of our prior conversation]\n'
                + summary
            ),
        },
        {
            'role': 'assistant',
            'content': 'I have the context from our previous conversation and am ready to continue.',
        },
    ]

